function B4DUI.AdminUI.Open() local f=B4DUI.UI.CreateFrame("B4D Admin",ScrW()*.7,ScrH()*.72); local y=90; for id,_ in SortedPairs(B4DUI.Admin.Actions) do local b=B4DUI.UI.Button(f,id,function() local tr=LocalPlayer():GetEyeTrace(); if IsValid(tr.Entity) and tr.Entity:IsPlayer() then B4DUI.RunAdminAction(id,tr.Entity,"",60) end end); b:SetPos(28,y); b:SetSize(180,32); y=y+38 end end
